const items = $input.all();
const cfg = {};
for (const item of items) {
  const name = (item.json.Name ?? '').trim();
  const value = item.json.Value;
  if (name && value != null && value !== '') {
    cfg[name] = value;
  }
}
const requiredKeys = [
  'Anthropic_ApiKey', 'OpenAI_ApiKey', 'Gemini_ApiKey',
  'Author_Model', 'Critic_Model', 'Moderator_Model',
  'Author_Thinking_Budget', 'Critic_Reasoning_Effort',
  'prompt_moderator_refiner', 'prompt_author', 'prompt_critic', 'prompt_moderator_validator',
  'Pass_Threshold', 'Max_Critique_Passes',
  'LogFolderId'
];
for (const key of requiredKeys) {
  if (!cfg[key]) {
    throw new Error('[Build Config] Missing required key: ' + key + '. Add it to EnvironmentVariables table.');
  }
}
return [{ json: cfg }];

const cfg = $('Code: Build Config').first().json;
const triggerData = $('Trigger: Form').first().json;

const draftPrompt = String(triggerData.draft_prompt || '').trim();
const extraContext = String(triggerData.extra_context || '').trim();

if (!draftPrompt) {
  throw new Error('[Build Refiner Payload] draft_prompt is required but was empty.');
}

const userText = extraContext
  ? 'Draft prompt:\n' + draftPrompt + '\n\nExtra context:\n' + extraContext
  : 'Draft prompt:\n' + draftPrompt;

return [{
  json: {
    draft_prompt: draftPrompt,
    extra_context: extraContext,
    gemini_payload: {
      system_instruction: { parts: [{ text: cfg.prompt_moderator_refiner }] },
      contents: [{ role: 'user', parts: [{ text: userText }] }],
      generationConfig: {
        responseMimeType: 'application/json',
        temperature: 0.2
      }
    }
  }
}];

function extractGeminiText(httpItem) {
  const parts = (httpItem && httpItem.candidates && httpItem.candidates[0] &&
    httpItem.candidates[0].content && httpItem.candidates[0].content.parts) || [];
  return parts.map(function(p) { return String(p.text || ''); }).join('\n');
}

function parseJsonObject(rawText) {
  if (!rawText) { throw new Error('Empty response text'); }
  const cleaned = String(rawText).trim()
    .replace(/^```[\w-]*[\r\n]+/, '')
    .replace(/[\r\n]+```$/, '')
    .trim();
  try {
    return JSON.parse(cleaned);
  } catch (err) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) { throw err; }
    return JSON.parse(match[0]);
  }
}

const httpItem = items[0].json;
const buildData = $('Code: Build Refiner Payload').first().json;

let parsed;
try {
  parsed = parseJsonObject(extractGeminiText(httpItem));
} catch (err) {
  throw new Error('[Parse Refined Prompt] Failed to parse Gemini refiner response: ' + err.message);
}

if (!parsed.refined_prompt) {
  throw new Error('[Parse Refined Prompt] Missing refined_prompt in Gemini response.');
}
if (!Array.isArray(parsed.rubric) || parsed.rubric.length === 0) {
  throw new Error('[Parse Refined Prompt] Missing or empty rubric in Gemini response.');
}

return [{
  json: {
    draft_prompt: buildData.draft_prompt,
    extra_context: buildData.extra_context,
    refined_prompt: String(parsed.refined_prompt),
    rubric: parsed.rubric,
    retry_count: 0,
    latest_author_output: null,
    iterations: []
  }
}];

const cfg = $('Code: Build Config').first().json;
const state = items[0].json;

const thinkingBudget = Number(cfg.Author_Thinking_Budget);
const maxTokens = thinkingBudget + 4096;

const userText = state.extra_context
  ? 'Prompt:\n' + state.refined_prompt + '\n\nExtra context:\n' + state.extra_context
  : 'Prompt:\n' + state.refined_prompt;

return [{
  json: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context,
    refined_prompt: state.refined_prompt,
    rubric: state.rubric,
    retry_count: state.retry_count,
    latest_author_output: state.latest_author_output,
    iterations: state.iterations,
    anthropic_payload: {
      model: cfg.Author_Model,
      max_tokens: maxTokens,
      thinking: { type: 'enabled', budget_tokens: thinkingBudget },
      system: cfg.prompt_author,
      messages: [{ role: 'user', content: userText }]
    }
  }
}];

function extractAnthropicText(httpItem) {
  const contentArr = Array.isArray(httpItem.content) ? httpItem.content : [];
  const text = contentArr
    .filter(function(block) { return block && block.type === 'text'; })
    .map(function(block) { return String(block.text || ''); })
    .join('\n')
    .trim();
  return text || String(httpItem.output_text || httpItem.completion || '');
}

const httpItem = items[0].json;
const buildData = $('Code: Build Author v1 Payload').first().json;

const contentArr = Array.isArray(httpItem.content) ? httpItem.content : [];
const thinkingBlocks = contentArr.filter(function(block) { return block && block.type === 'thinking'; });
const authorText = extractAnthropicText(httpItem);

if (!authorText) {
  throw new Error('[Parse Author v1] Empty text response from Author v1.');
}

return [{
  json: {
    draft_prompt: buildData.draft_prompt,
    extra_context: buildData.extra_context,
    refined_prompt: buildData.refined_prompt,
    rubric: buildData.rubric,
    retry_count: buildData.retry_count,
    latest_author_output: authorText,
    author_thinking_current: thinkingBlocks,
    iterations: buildData.iterations
  }
}];

const cfg = $('Code: Build Config').first().json;
const state = items[0].json;

const userText = 'Refined prompt:\n' + state.refined_prompt +
  '\n\nAuthor output:\n' + state.latest_author_output;

return [{
  json: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context,
    refined_prompt: state.refined_prompt,
    rubric: state.rubric,
    retry_count: state.retry_count,
    latest_author_output: state.latest_author_output,
    author_thinking_current: state.author_thinking_current || [],
    iterations: state.iterations || [],
    openai_payload: {
      model: cfg.Critic_Model,
      reasoning_effort: cfg.Critic_Reasoning_Effort,
      response_format: { type: 'json_object' },
      messages: [
        { role: 'system', content: cfg.prompt_critic },
        { role: 'user', content: userText }
      ]
    }
  }
}];

function extractOpenAIText(httpItem) {
  return String((httpItem && httpItem.choices && httpItem.choices[0] &&
    httpItem.choices[0].message && httpItem.choices[0].message.content) || '');
}

function parseJsonObject(rawText) {
  if (!rawText) { throw new Error('Empty response text'); }
  const cleaned = String(rawText).trim()
    .replace(/^```[\w-]*[\r\n]+/, '')
    .replace(/[\r\n]+```$/, '')
    .trim();
  try {
    return JSON.parse(cleaned);
  } catch (err) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) { throw err; }
    return JSON.parse(match[0]);
  }
}

const httpItem = items[0].json;
const buildData = $('Code: Build Critic Payload').first().json;

let criticJson;
try {
  criticJson = parseJsonObject(extractOpenAIText(httpItem));
} catch (err) {
  throw new Error('[Parse Critic Response] Failed to parse Critic response: ' + err.message);
}

return [{
  json: {
    draft_prompt: buildData.draft_prompt,
    extra_context: buildData.extra_context,
    refined_prompt: buildData.refined_prompt,
    rubric: buildData.rubric,
    retry_count: buildData.retry_count,
    latest_author_output: buildData.latest_author_output,
    author_thinking_current: buildData.author_thinking_current,
    iterations: buildData.iterations,
    critic_json: criticJson
  }
}];

const cfg = $('Code: Build Config').first().json;
const state = items[0].json;

const thinkingBudget = Number(cfg.Author_Thinking_Budget);
const maxTokens = thinkingBudget + 4096;

const userText = 'Refined prompt:\n' + state.refined_prompt +
  '\n\nPrevious author output:\n' + state.latest_author_output +
  '\n\nCritic feedback:\n' + JSON.stringify(state.critic_json, null, 2) +
  '\n\nInstruction: Produce the revised version. Address each item in suggested_revisions explicitly. Preserve the strengths identified.';

return [{
  json: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context,
    refined_prompt: state.refined_prompt,
    rubric: state.rubric,
    retry_count: state.retry_count,
    latest_author_output: state.latest_author_output,
    author_thinking_current: state.author_thinking_current,
    iterations: state.iterations,
    critic_json: state.critic_json,
    anthropic_payload: {
      model: cfg.Author_Model,
      max_tokens: maxTokens,
      thinking: { type: 'enabled', budget_tokens: thinkingBudget },
      system: cfg.prompt_author,
      messages: [{ role: 'user', content: userText }]
    }
  }
}];

function extractAnthropicText(httpItem) {
  const contentArr = Array.isArray(httpItem.content) ? httpItem.content : [];
  const text = contentArr
    .filter(function(block) { return block && block.type === 'text'; })
    .map(function(block) { return String(block.text || ''); })
    .join('\n')
    .trim();
  return text || String(httpItem.output_text || httpItem.completion || '');
}

const httpItem = items[0].json;
const buildData = $('Code: Build Author Revision Payload').first().json;

const contentArr = Array.isArray(httpItem.content) ? httpItem.content : [];
const thinkingBlocks = contentArr.filter(function(block) { return block && block.type === 'thinking'; });
const revisedText = extractAnthropicText(httpItem);

if (!revisedText) {
  throw new Error('[Parse Author Revision] Empty text response from Author revision.');
}

return [{
  json: {
    draft_prompt: buildData.draft_prompt,
    extra_context: buildData.extra_context,
    refined_prompt: buildData.refined_prompt,
    rubric: buildData.rubric,
    retry_count: buildData.retry_count,
    latest_author_output: revisedText,
    author_thinking_current: thinkingBlocks,
    iterations: buildData.iterations,
    critic_json: buildData.critic_json
  }
}];

const cfg = $('Code: Build Config').first().json;
const state = items[0].json;

const userText = 'Refined prompt:\n' + state.refined_prompt +
  '\n\nRubric:\n' + JSON.stringify(state.rubric, null, 2) +
  '\n\nAuthor output to validate:\n' + state.latest_author_output;

return [{
  json: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context,
    refined_prompt: state.refined_prompt,
    rubric: state.rubric,
    retry_count: state.retry_count,
    latest_author_output: state.latest_author_output,
    author_thinking_current: state.author_thinking_current,
    iterations: state.iterations,
    critic_json: state.critic_json,
    gemini_payload: {
      system_instruction: { parts: [{ text: cfg.prompt_moderator_validator }] },
      contents: [{ role: 'user', parts: [{ text: userText }] }],
      generationConfig: {
        responseMimeType: 'application/json',
        temperature: 0.2
      }
    }
  }
}];

function extractGeminiText(httpItem) {
  const parts = (httpItem && httpItem.candidates && httpItem.candidates[0] &&
    httpItem.candidates[0].content && httpItem.candidates[0].content.parts) || [];
  return parts.map(function(p) { return String(p.text || ''); }).join('\n');
}

function parseJsonObject(rawText) {
  if (!rawText) { throw new Error('Empty response text'); }
  const cleaned = String(rawText).trim()
    .replace(/^```[\w-]*[\r\n]+/, '')
    .replace(/[\r\n]+```$/, '')
    .trim();
  try {
    return JSON.parse(cleaned);
  } catch (err) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) { throw err; }
    return JSON.parse(match[0]);
  }
}

const httpItem = items[0].json;
const buildData = $('Code: Build Validator Payload').first().json;

let validatorJson;
try {
  validatorJson = parseJsonObject(extractGeminiText(httpItem));
} catch (err) {
  throw new Error('[Parse Validator Response] Failed to parse Gemini validator response: ' + err.message);
}

const overallScore = Number(validatorJson.overall_score) || 0;

const iterationEntry = {
  iteration: buildData.retry_count,
  author_output: buildData.latest_author_output,
  author_thinking: buildData.author_thinking_current,
  critic_json: buildData.critic_json,
  validator_json: validatorJson
};

const updatedIterations = (buildData.iterations || []).concat([iterationEntry]);

return [{
  json: {
    draft_prompt: buildData.draft_prompt,
    extra_context: buildData.extra_context,
    refined_prompt: buildData.refined_prompt,
    rubric: buildData.rubric,
    retry_count: buildData.retry_count,
    latest_author_output: buildData.latest_author_output,
    author_thinking_current: buildData.author_thinking_current,
    iterations: updatedIterations,
    validator_json: validatorJson,
    overall_score: overallScore
  }
}];

const state = items[0].json;
return [{
  json: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context,
    refined_prompt: state.refined_prompt,
    rubric: state.rubric,
    retry_count: (state.retry_count || 0) + 1,
    latest_author_output: state.latest_author_output,
    author_thinking_current: state.author_thinking_current || [],
    iterations: state.iterations || []
  }
}];

const cfg = $('Code: Build Config').first().json;
const state = items[0].json;

const ts = new Date().toISOString();
const filename = 'deliberation_' + ts.replace(/[:.]/g, '-') + '.json';

const trace = {
  timestamp: ts,
  input: {
    draft_prompt: state.draft_prompt,
    extra_context: state.extra_context || ''
  },
  refined_prompt: state.refined_prompt,
  rubric: state.rubric,
  iterations: state.iterations || [],
  final_output: state.latest_author_output,
  final_verdict: (state.validator_json && state.validator_json.verdict)
    ? state.validator_json.verdict
    : 'UNKNOWN',
  retry_count: state.retry_count || 0,
  models_used: {
    author: cfg.Author_Model,
    critic: cfg.Critic_Model,
    moderator: cfg.Moderator_Model
  }
};

const traceJson = JSON.stringify(trace, null, 2);
const buffer = Buffer.from(traceJson, 'utf8');

return [{
  json: {
    trace_filename: filename,
    latest_author_output: state.latest_author_output,
    validator_json: state.validator_json || {},
    retry_count: state.retry_count || 0
  },
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'application/json',
      fileName: filename,
      fileExtension: 'json'
    }
  }
}];

const traceData = $('Code: Build Trace').first().json;
const validatorJson = traceData.validator_json || {};

return [{
  json: {
    status: String(validatorJson.verdict || 'UNKNOWN'),
    final_output: traceData.latest_author_output,
    validator_summary: {
      overall_score: Number(validatorJson.overall_score) || 0,
      verdict: String(validatorJson.verdict || 'UNKNOWN'),
      recommendation: String(validatorJson.recommendation || '')
    },
    retry_count: traceData.retry_count || 0
  }
}];
